+/// Build `ListFilters` from the JSON arguments, collecting coercion warnings.
+fn build_list_filters(
+    args: &serde_json::Value,
+    coercions: &mut Vec<String>,
+) -> McpResult<ListFilters> {
+    let statuses = args
+        .get("status")
+        .and_then(|v| v.as_str())
+        .map(|s| {
+            s.split(',')
+                .map(|p| {
+                    let (status, warning) = parse_status(p.trim())?;
+                    if let Some(w) = warning {
+                        coercions.push(w);
+                    }
+                    Ok(status)
+                })
+                .collect::<McpResult<Vec<_>>>()
+        })
+        .transpose()?;
+
+    let types = args
+        .get("type")
+        .and_then(|v| v.as_str())
+        .map(|s| {
+            s.split(',')
+                .map(|p| {
+                    let (t, warning) = parse_issue_type(p.trim());
+                    if let Some(w) = warning {
+                        coercions.push(w);
+                    }
+                    t
+                })
+                .collect::<Vec<_>>()
+        });
+
+    let priorities = args
+        .get("priority")
+        .and_then(|v| v.as_str())
+        .map(|s| {
+            s.split(',')
+                .map(|p| {
+                    let (prio, warning) = parse_priority(p.trim())?;
+                    if let Some(w) = warning {
+                        coercions.push(w);
+                    }
+                    Ok(prio)
+                })
+                .collect::<McpResult<Vec<_>>>()
+        })
+        .transpose()?;
+
+    let labels = args
+        .get("labels")
+        .and_then(|v| v.as_str())
+        .map(|s| s.split(',').map(|l| l.trim().to_string()).collect::<Vec<_>>());
+
+    let include_closed = args
+        .get("include_closed")
+        .and_then(serde_json::Value::as_bool)
+        .unwrap_or(false);
+
+    let raw_limit = args
+        .get("limit")
+        .and_then(serde_json::Value::as_u64)
+        .unwrap_or(50);
+    let limit = Some(raw_limit.min(500) as usize);
+
+    let sort = args
+        .get("sort")
+        .and_then(|v| v.as_str())
+        .map(String::from);
+
+    let title_contains = args
+        .get("title")
+        .and_then(|v| v.as_str())
+        .map(String::from);
+
+    // Forgive by Default: if the status filter includes Deferred, automatically
+    // enable include_deferred so the query doesn't contradict itself.
+    let include_deferred = statuses
+        .as_ref()
+        .is_some_and(|s| s.contains(&Status::Deferred));
+
+    Ok(ListFilters {
+        statuses,
+        types,
+        priorities,
+        assignee: args
+            .get("assignee")
+            .and_then(|v| v.as_str())
+            .map(String::from),
+        include_closed,
+        include_deferred,
+        limit,
+        sort,
+        labels,
+        title_contains,
+        ..ListFilters::default()
+    })
+}
